import React, { useState } from 'react'
import type { StaticImageData } from 'next/image'

const ERROR_IMG_SRC =
  'data:image/svg+xml;base64,'

type ImgSrc = string | Blob | StaticImageData

export function ImageWithFallback(
  props: Omit<React.ImgHTMLAttributes<HTMLImageElement>, 'src'> & { src?: ImgSrc }
) {
  const [didError, setDidError] = useState(false)

  const handleError = () => {
    setDidError(true)
  }

  const { src, alt, style, className, ...rest } = props
  const resolvedSrc =
    typeof src === 'string' || typeof src === 'undefined'
      ? src
      : src instanceof Blob
        ? URL.createObjectURL(src)
        : src.src

  return didError ? (
    <div
      className={`inline-block bg-gray-100 text-center align-middle ${className ?? ''}`}
      style={style}
    >
      <div className="flex items-center justify-center w-full h-full">
        <img src={ERROR_IMG_SRC} alt="Error loading image" {...rest} data-original-url={resolvedSrc} />
      </div>
    </div>
  ) : (
    <img src={resolvedSrc} alt={alt} className={className} style={style} {...rest} onError={handleError} />
  )
}
